import { Injectable } from "@angular/core";
import { CommonHttpModule } from "../../providers/commonHttpModule";
import { map, Observable } from "rxjs";
import { Disbursment, DisbursmentDetails } from "../../pages/disbursment/disbursment.component.model";

@Injectable({
    providedIn: "root"
})
export class ClientApprovalService {

    constructor(private http: CommonHttpModule) { }

    getClientData(params: any): Observable<{ data: Disbursment[]; total_count: number }> {
        return this.http.post<{ total_count: number, data: Disbursment[] }>("client-list", params)
            .pipe(
                map(response => ({
                    total_count: response.total_count,
                    data: response.data
                }))
            );
    }
    // method to get the disbursementDtl from db

    getClentDataDtls(params: any): Observable<{ data: DisbursmentDetails }> {
        return this.http.get<{ data: DisbursmentDetails }>(`disbursement_tracker_detail/${params}`, {})
            .pipe(
                map((response) => {
                    return response;
                })
            );
    }


    pdaClientApprovalDataToDb(data: any) {
        return this.http.post('pda_client_form_submit', data).pipe(
            map((response) => {
                return response;
            })
        );
    }

    fdaClientApprovalDataToDb(data: any) {
        return this.http.post('FDA_client_form_submit', data).pipe(
            map((response) => {
                return response;
            })
        );
    }

}