  // method to get the vessel based on the client
  vesselListByClientId(clientId: number): Promise<void> {
    return new Promise<void>((resolve, reject) => {
      this.loader.show();

      const vslpayload = {
        company_id: clientId,
        fields: ["assigned_unassigned"]
      };

      this.clientService.VslListFromDb(vslpayload).subscribe({
        next: (response: any) => {
          const vesselDetails = this.pdaOrFda === 'PDA'
            ? this.clientData?.pda?.pda_vessel_details
            : this.clientData?.fda?.fda_vessel_details;

          this.vesselList = mergeResponseVesselIntoList(response.assigned_vessels || [], vesselDetails);

          this.fields.map((field) => {
            if (field.name === 'Vessel') {
              field.options = this.vesselList.map((vessel: any) => ({
                vessel_id: vessel.vessel_id,
                name: vessel.name
              }));
            }
            this.filteredOptions[field.value] = field.options;
          });
          this.loader.hide();
          resolve();
        },
        error: (error: any) => {
          this.vesselList = [];
          this.errMsg = error?.error?.error || 'Failed to fetch vessel details';
          this.snackBar.showError(this.errMsg);
          this.loader.hide();
          reject(error);
        }
      });
    });
  }


